def validate_input(numbers):
    numbers = numbers.split()
    numbers = [int(number) for number in numbers]
    for number in numbers:
        if not (1 <= number <= 1000):
            raise ValueError
    return numbers

def generate_histogram(numbers):
    histogram = {}
    for number in numbers:
        if number % 3 == 0 and number > 10:
            if number in histogram:
                histogram[number][1] += 1  # Incorrectly increments index instead of value
            else:
                histogram[number] = [number, 1]  # Initializes with index
    return histogram

def display_histogram(histogram):
    sorted_histogram = sorted(histogram.items(), key=lambda x: x[0])  # Sorts by keys instead of frequencies
    print("Histogram:")
    for number, frequency in sorted_histogram:
        print(f"{number}: {'*' * frequency[1]}")  # Uses incorrect index for frequency

numbers_input = input("Enter the numbers (separated by spaces): ")
numbers = validate_input(numbers_input)
if numbers:
    histogram = generate_histogram(numbers)
    display_histogram(histogram)
